.darma-loader-darma-custom-643__Strich1 {color: var(--loader-color, #db2777);

  position: relative;
  width: 130px;
  height: 50px;
  background: var(--loader-color, #db2777);
  border-radius: 25px;
  transform: rotate(45deg);
  box-shadow: 0 4px 10px color-mix(in srgb, var(--loader-color, #db2777) 45%, transparent);
  z-index: 0;
}
.darma-loader-darma-custom-643__Strich2 {
  position: absolute;
  width: 130px;
  height: 50px;
  background: var(--loader-color, #db2777);
  border-radius: 25px;
  transform: rotate(-90deg);
  box-shadow: 0 4px 10px color-mix(in srgb, var(--loader-color, #db2777) 45%, transparent);
  z-index: 0;
}

.darma-loader-darma-custom-643__bubble {
  position: absolute;
  top: 0;
  left: 15px;
  width: 20px;
  height: 20px;
  border-radius: 50%;
  background: radial-gradient(circle at 30% 30%, #ffb3c1, #e64980, #ff8787);
  animation: darma-loader-darma-custom-643-dropAndShift 5s ease-in-out infinite;
  z-index: 1;
}

.darma-loader-darma-custom-643__bubble1 {
  position: absolute;
  top: 0;
  width: 20px;
  height: 20px;
  background: radial-gradient(circle at 30% 30%, #edb3ff, #ac49e6, #fb87ff);
  border-radius: 50%;
  left: 8px;
  animation: darma-loader-darma-custom-643-dropAndShift 6s ease-in-out infinite;
  z-index: 2;
}
.darma-loader-darma-custom-643__bubble2 {
  position: absolute;
  top: 0;
  width: 20px;
  height: 20px;
  background: radial-gradient(circle at 30% 30%, #b3d8ff, #4963e6, #87a7ff);
  border-radius: 50%;
  left: 12px;
  animation: darma-loader-darma-custom-643-dropAndShift 4s ease-in-out infinite;
  z-index: 3;
}
.darma-loader-darma-custom-643__bubble3 {
  position: absolute;
  top: 0;
  width: 20px;
  height: 20px;
  background: radial-gradient(circle at 30% 30%, #b3ffbc, #35a32f, #75ba61);
  border-radius: 50%;
  left: 10px;
  animation: darma-loader-darma-custom-643-dropAndShift 7s ease-in-out infinite;
  z-index: 4;
}

